164	export function createAmazonBedrock(
165	  options: AmazonBedrockProviderSettings = {},
166	): AmazonBedrockProvider {
167	  // Check for API key authentication first
168	  const rawApiKey = loadOptionalSetting({
169	    settingValue: options.apiKey,
170	    environmentVariableName: 'AWS_BEARER_TOKEN_BEDROCK',
171	  });
172	
173	  // FIX 1: Validate API key to ensure proper fallback to SigV4
174	  // Only use API key if it's a non-empty, non-whitespace string
175	  const apiKey =
176	    rawApiKey && rawApiKey.trim().length > 0 ? rawApiKey.trim() : undefined;
177	
178	  // Use API key authentication if available, otherwise fall back to SigV4
179	  const fetchFunction = apiKey
180	    ? createApiKeyFetchFunction(apiKey, options.fetch)
181	    : createSigV4FetchFunction(async () => {
182	        const region = loadSetting({
183	          settingValue: options.region,
184	          settingName: 'region',
185	          environmentVariableName: 'AWS_REGION',
186	          description: 'AWS region',
187	        });
188	
189	        // If a credential provider is provided, use it to get the credentials.
190	        if (options.credentialProvider) {
191	          try {
192	            return {
193	              ...(await options.credentialProvider()),
194	              region,
195	            };
196	          } catch (error) {
197	            // Error handling for credential provider failures
198	            const errorMessage =
199	              error instanceof Error ? error.message : String(error);
200	            throw new Error(
201	              `AWS credential provider failed: ${errorMessage}. ` +
202	                'Please ensure your credential provider returns valid AWS credentials ' +
203	                'with accessKeyId and secretAccessKey properties.',
204	            );
205	          }
206	        }
207	
208	        // Enhanced error handling for SigV4 credential loading
209	        try {
210	          return {
211	            region,
212	            accessKeyId: loadSetting({
213	              settingValue: options.accessKeyId,
214	              settingName: 'accessKeyId',
215	              environmentVariableName: 'AWS_ACCESS_KEY_ID',
216	              description: 'AWS access key ID',
217	            }),
218	            secretAccessKey: loadSetting({
219	              settingValue: options.secretAccessKey,
220	              settingName: 'secretAccessKey',
221	              environmentVariableName: 'AWS_SECRET_ACCESS_KEY',
222	              description: 'AWS secret access key',
223	            }),
224	            sessionToken: loadOptionalSetting({
225	              settingValue: options.sessionToken,
226	              environmentVariableName: 'AWS_SESSION_TOKEN',
227	            }),
228	          };
229	        } catch (error) {
230	          // Provide helpful error message for missing AWS credentials
231	          const errorMessage =
232	            error instanceof Error ? error.message : String(error);
233	          if (
234	            errorMessage.includes('AWS_ACCESS_KEY_ID') ||
235	            errorMessage.includes('accessKeyId')
236	          ) {
237	            throw new Error(
238	              'AWS SigV4 authentication requires AWS credentials. Please provide either:\n' +
239	                '1. Set AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY environment variables\n' +
240	                '2. Provide accessKeyId and secretAccessKey in options\n' +
241	                '3. Use a credentialProvider function\n' +
242	                '4. Use API key authentication with AWS_BEARER_TOKEN_BEDROCK or apiKey option\n' +
243	                `Original error: ${errorMessage}`,
244	            );
245	          }
246	          if (
247	            errorMessage.includes('AWS_SECRET_ACCESS_KEY') ||
248	            errorMessage.includes('secretAccessKey')
249	          ) {
250	            throw new Error(
251	              'AWS SigV4 authentication requires both AWS_ACCESS_KEY_ID and AWS_SECRET_ACCESS_KEY. ' +
252	                'Please ensure both credentials are provided.\n' +
253	                `Original error: ${errorMessage}`,
254	            );
255	          }
256	          // Re-throw other errors as-is
257	          throw error;
258	        }
259	      }, options.fetch);
260	
261	  const getHeaders = () => {
262	    const baseHeaders = options.headers ?? {};
263	    return withUserAgentSuffix(baseHeaders, `ai-sdk/amazon-bedrock/${VERSION}`);
264	  };
265	
266	  const getBedrockRuntimeBaseUrl = (): string =>
267	    withoutTrailingSlash(
268	      options.baseURL ??
269	        `https://bedrock-runtime.${loadSetting({
270	          settingValue: options.region,
271	          settingName: 'region',
272	          environmentVariableName: 'AWS_REGION',
273	          description: 'AWS region',
274	        })}.amazonaws.com`,
275	    ) ?? `https://bedrock-runtime.us-east-1.amazonaws.com`;
276	
277	  const getBedrockAgentRuntimeBaseUrl = (): string =>
278	    withoutTrailingSlash(
279	      options.baseURL ??
280	        `https://bedrock-agent-runtime.${loadSetting({
281	          settingValue: options.region,
282	          settingName: 'region',
283	          environmentVariableName: 'AWS_REGION',
284	          description: 'AWS region',
285	        })}.amazonaws.com`,
286	    ) ?? `https://bedrock-agent-runtime.us-west-2.amazonaws.com`;
287	
288	  const createChatModel = (modelId: BedrockChatModelId) =>
289	    new BedrockChatLanguageModel(modelId, {
290	      baseUrl: getBedrockRuntimeBaseUrl,
291	      headers: getHeaders,
292	      fetch: fetchFunction,
293	      generateId,
294	    });
295	
296	  const provider = function (modelId: BedrockChatModelId) {
297	    if (new.target) {
298	      throw new Error(
299	        'The Amazon Bedrock model function cannot be called with the new keyword.',
300	      );
301	    }
302	
303	    return createChatModel(modelId);
304	  };
305	
306	  const createEmbeddingModel = (modelId: BedrockEmbeddingModelId) =>
307	    new BedrockEmbeddingModel(modelId, {
308	      baseUrl: getBedrockRuntimeBaseUrl,
309	      headers: getHeaders,
310	      fetch: fetchFunction,
311	    });
312	
313	  const createImageModel = (modelId: BedrockImageModelId) =>
314	    new BedrockImageModel(modelId, {
315	      baseUrl: getBedrockRuntimeBaseUrl,
316	      headers: getHeaders,
317	      fetch: fetchFunction,
318	    });
319	
320	  const createRerankingModel = (modelId: BedrockRerankingModelId) =>
321	    new BedrockRerankingModel(modelId, {
322	      baseUrl: getBedrockAgentRuntimeBaseUrl,
323	      region: loadSetting({
324	        settingValue: options.region,
325	        settingName: 'region',
326	        environmentVariableName: 'AWS_REGION',
327	        description: 'AWS region',
328	      }),
329	      headers: getHeaders,
330	      fetch: fetchFunction,
331	    });
332	
333	  provider.specificationVersion = 'v3' as const;
334	  provider.languageModel = createChatModel;
335	  provider.embedding = createEmbeddingModel;
336	  provider.embeddingModel = createEmbeddingModel;
337	  provider.textEmbedding = createEmbeddingModel;
338	  provider.textEmbeddingModel = createEmbeddingModel;
339	  provider.image = createImageModel;
340	  provider.imageModel = createImageModel;
341	  provider.reranking = createRerankingModel;
342	  provider.rerankingModel = createRerankingModel;
343	  provider.tools = anthropicTools;
344	
345	  return provider;
346	}
