#### C. `src/image/your-provider-image-model.ts` - COMPLETE IMPLEMENTATION

```typescript
import {
  ImageModelV3,
  ImageModelV3File,
  SharedV3Warning,
} from '@ai-sdk/provider';
import {
  combineHeaders,
  convertBase64ToUint8Array,
  convertToFormData,
  createJsonResponseHandler,
  downloadBlob,
  postFormDataToApi,
  postJsonToApi,
} from '@ai-sdk/provider-utils';
import { YourProviderConfig } from '../your-provider-config';
import { yourProviderFailedResponseHandler } from '../your-provider-error';
import { yourProviderImageResponseSchema } from './your-provider-image-api';
import {
  YourProviderImageModelId,
  modelMaxImagesPerCall,
} from './your-provider-image-options';

interface YourProviderImageModelConfig extends YourProviderConfig {
  _internal?: {
    currentDate?: () => Date;
  };
}

export class YourProviderImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  get maxImagesPerCall(): number {
    return modelMaxImagesPerCall[this.modelId] ?? 1;
  }

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: YourProviderImageModelId,
    private readonly config: YourProviderImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    files,
    mask,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    // Handle unsupported features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    // CASE 1: Image editing (files provided)
    if (files != null && files.length > 0) {
      const { value: response, responseHeaders } = await postFormDataToApi({
        url: this.config.url({
          path: '/images/edits',
          modelId: this.modelId,
        }),
        headers: combineHeaders(this.config.headers(), headers),
        formData: convertToFormData({
          model: this.modelId,
          prompt,
          image: await Promise.all(
            files.map(file => fileToBlob(file)),
          ),
          mask: mask != null ? await fileToBlob(mask) : undefined,
          n,
          size,
          ...(providerOptions?.yourProvider ?? {}),
        }),
        failedResponseHandler: yourProviderFailedResponseHandler,
        successfulResponseHandler: createJsonResponseHandler(
          yourProviderImageResponseSchema,
        ),
        abortSignal,
        fetch: this.config.fetch,
      });

      return {
        images: response.data.map(item => item.b64_json),
        warnings,
        usage:
          response.usage != null
            ? {
                inputTokens: response.usage.input_tokens ?? undefined,
                outputTokens: response.usage.output_tokens ?? undefined,
                totalTokens: response.usage.total_tokens ?? undefined,
              }
            : undefined,
        response: {
          timestamp: currentDate,
          modelId: this.modelId,
          headers: responseHeaders,
        },
        providerMetadata: {
          yourProvider: {
            images: response.data.map(item => ({
              ...(item.revised_prompt
                ? { revisedPrompt: item.revised_prompt }
                : {}),
              created: response.created ?? undefined,
              size: response.size ?? undefined,
              quality: response.quality ?? undefined,
            })),
          },
        },
      };
    }

    // CASE 2: Text-to-image generation
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generations',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size,
        ...(providerOptions.yourProvider ?? {}),
      },
      failedResponseHandler: yourProviderFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        yourProviderImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      usage:
        response.usage != null
          ? {
              inputTokens: response.usage.input_tokens ?? undefined,
              outputTokens: response.usage.output_tokens ?? undefined,
              totalTokens: response.usage.total_tokens ?? undefined,
            }
          : undefined,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        yourProvider: {
          images: response.data.map(item => ({
            ...(item.revised_prompt
              ? { revisedPrompt: item.revised_prompt }
              : {}),
            created: response.created ?? undefined,
            size: response.size ?? undefined,
            quality: response.quality ?? undefined,
          })),
        },
      },
    };
  }
}

async function fileToBlob(
  file: ImageModelV3File | undefined,
): Promise<Blob | undefined> {
  if (!file) return undefined;

  if (file.type === 'url') {
    return downloadBlob(file.url);
  }

  const data =
    file.data instanceof Uint8Array
      ? file.data
      : convertBase64ToUint8Array(file.data);

  return new Blob([data as BlobPart], { type: file.mediaType });
}
```

### 4. PROVIDER FACTORY FILE (`src/your-provider-provider.ts`)

This is the main entry point that ties everything together:

```typescript
import {
  EmbeddingModelV3,
  ImageModelV3,
  LanguageModelV3,
  ProviderV3,
  SpeechModelV3,
  TranscriptionModelV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { YourProviderChatLanguageModel } from './chat/your-provider-chat-language-model';
import { YourProviderChatModelId } from './chat/your-provider-chat-options';
import { YourProviderEmbeddingModel } from './embedding/your-provider-embedding-model';
import { YourProviderEmbeddingModelId } from './embedding/your-provider-embedding-options';
import { YourProviderImageModel } from './image/your-provider-image-model';
import { YourProviderImageModelId } from './image/your-provider-image-options';
import { VERSION } from './version';

export interface YourProviderProvider extends ProviderV3 {
  (modelId: YourProviderChatModelId): LanguageModelV3;

  languageModel(modelId: YourProviderChatModelId): LanguageModelV3;
  chat(modelId: YourProviderChatModelId): LanguageModelV3;

  embedding(modelId: YourProviderEmbeddingModelId): EmbeddingModelV3;
  embeddingModel(modelId: YourProviderEmbeddingModelId): EmbeddingModelV3;

  image(modelId: YourProviderImageModelId): ImageModelV3;
  imageModel(modelId: YourProviderImageModelId): ImageModelV3;
}

export interface YourProviderProviderSettings {
  baseURL?: string;
  apiKey?: string;
  headers?: Record<string, string>;
  name?: string;
  fetch?: FetchFunction;
}

/**
 * Create a Your Provider instance.
 */
export function createYourProvider(
  options: YourProviderProviderSettings = {},
): YourProviderProvider {
  const baseURL =
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'YOUR_PROVIDER_BASE_URL',
      }),
    ) ?? 'https://api.yourprovider.com/v1';

  const providerName = options.name ?? 'your-provider';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'YOUR_PROVIDER_API_KEY',
          description: 'Your Provider',
        })}`,
        ...options.headers,
      },
      `ai-sdk/your-provider/${VERSION}`,
    );

  const createChatModel = (modelId: YourProviderChatModelId) =>
    new YourProviderChatLanguageModel(modelId, {
      provider: `${providerName}.chat`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createEmbeddingModel = (modelId: YourProviderEmbeddingModelId) =>
    new YourProviderEmbeddingModel(modelId, {
      provider: `${providerName}.embedding`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createImageModel = (modelId: YourProviderImageModelId) =>
    new YourProviderImageModel(modelId, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createLanguageModel = (modelId: YourProviderChatModelId) => {
    if (new.target) {
      throw new Error(
        'The Your Provider model function cannot be called with the new keyword.',
      );
    }
    return createChatModel(modelId);
  };

  const provider = function (modelId: YourProviderChatModelId) {
    return createLanguageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createLanguageModel;
  provider.chat = createChatModel;
  provider.embedding = createEmbeddingModel;
  provider.embeddingModel = createEmbeddingModel;
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider as YourProviderProvider;
}

export const yourProvider = createYourProvider();
```

### 5. CONFIG INTERFACE (`src/your-provider-config.ts`)

```typescript
import { FetchFunction } from '@ai-sdk/provider-utils';

export type YourProviderConfig = {
  provider: string;
  url: (options: { modelId: string; path: string }) => string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  generateId?: () => string;
};
```

### 6. MAIN INDEX FILE (`src/index.ts`)

```typescript
export { createYourProvider, yourProvider } from './your-provider-provider';
export type { 
  YourProviderProvider, 
  YourProviderProviderSettings 
} from './your-provider-provider';
export type { 
  YourProviderLanguageModelChatOptions 
} from './chat/your-provider-chat-options';
export type { 
  YourProviderEmbeddingModelOptions 
} from './embedding/your-provider-embedding-options';
export { VERSION } from './version';
```

### 7. COMPARISON: OpenAI vs Google vs Amazon Bedrock Image Implementations

| Aspect | OpenAI | Google | Amazon Bedrock |
|--------|--------|--------|-----------------|
| **Edit Support** | Full (edits + inpainting) | Limited (Gemini only) | Extensive (4 task types) |
