```typescript
import {
  EmbeddingModelV3,
  ImageModelV3,
  LanguageModelV3,
  ProviderV3,
  SpeechModelV3,
  TranscriptionModelV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { YourProviderChatLanguageModel } from './chat/your-provider-chat-language-model';
import { YourProviderChatModelId } from './chat/your-provider-chat-options';
import { YourProviderEmbeddingModel } from './embedding/your-provider-embedding-model';
import { YourProviderEmbeddingModelId } from './embedding/your-provider-embedding-options';
import { YourProviderImageModel } from './image/your-provider-image-model';
import { YourProviderImageModelId } from './image/your-provider-image-options';
import { VERSION } from './version';

export interface YourProviderProvider extends ProviderV3 {
  (modelId: YourProviderChatModelId): LanguageModelV3;

  languageModel(modelId: YourProviderChatModelId): LanguageModelV3;
  chat(modelId: YourProviderChatModelId): LanguageModelV3;

  embedding(modelId: YourProviderEmbeddingModelId): EmbeddingModelV3;
  embeddingModel(modelId: YourProviderEmbeddingModelId): EmbeddingModelV3;

  image(modelId: YourProviderImageModelId): ImageModelV3;
  imageModel(modelId: YourProviderImageModelId): ImageModelV3;
}

export interface YourProviderProviderSettings {
  baseURL?: string;
  apiKey?: string;
  headers?: Record<string, string>;
  name?: string;
  fetch?: FetchFunction;
}

/**
 * Create a Your Provider instance.
 */
export function createYourProvider(
  options: YourProviderProviderSettings = {},
): YourProviderProvider {
  const baseURL =
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'YOUR_PROVIDER_BASE_URL',
      }),
    ) ?? 'https://api.yourprovider.com/v1';

  const providerName = options.name ?? 'your-provider';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'YOUR_PROVIDER_API_KEY',
          description: 'Your Provider',
        })}`,
        ...options.headers,
      },
      `ai-sdk/your-provider/${VERSION}`,
    );

  const createChatModel = (modelId: YourProviderChatModelId) =>
    new YourProviderChatLanguageModel(modelId, {
      provider: `${providerName}.chat`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createEmbeddingModel = (modelId: YourProviderEmbeddingModelId) =>
    new YourProviderEmbeddingModel(modelId, {
      provider: `${providerName}.embedding`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createImageModel = (modelId: YourProviderImageModelId) =>
    new YourProviderImageModel(modelId, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createLanguageModel = (modelId: YourProviderChatModelId) => {
    if (new.target) {
      throw new Error(
        'The Your Provider model function cannot be called with the new keyword.',
      );
    }
    return createChatModel(modelId);
  };

  const provider = function (modelId: YourProviderChatModelId) {
    return createLanguageModel(modelId);
  };

  provider.specificationVersion = 'v3' as const;
  provider.languageModel = createLanguageModel;
  provider.chat = createChatModel;
  provider.embedding = createEmbeddingModel;
  provider.embeddingModel = createEmbeddingModel;
  provider.image = createImageModel;
  provider.imageModel = createImageModel;

  return provider as YourProviderProvider;
}

export const yourProvider = createYourProvider();
```

