  'pixelart-v1': 4,
  'pixelart-v2': 4,
  'pixelart-retro': 1,
};

/**
 * Settings for a PixelArt image generation request.
 */
export interface PixelArtImageSettings {
  /**
   * The desired output image size (e.g. "256x256", "512x512", "1024x1024").
   */
  size?: string;

  /**
   * The pixel-art style to apply to the generated image.
   * - "pixel"  – classic pixel-art look (default)
   * - "retro"  – 8-bit / 16-bit retro video-game aesthetic
   * - "8bit"   – strict 8-bit color palette
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density (pixels per unit) used when rendering the output.
   * Higher values produce finer-grained pixel art.
   * Typical range: 1–16.
   */
  pixelDensity?: number;
}

