import { ImageModelV3, ProviderV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-options';
import { VERSION } from './version';

/**
 * PixelArt provider interface.
 * Only image generation is supported.
 */
export interface PixelArtProvider extends Pick<ProviderV3, 'specificationVersion'> {
  /**
   * Creates a PixelArt image generation model.
   */
  image(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;

  /**
   * Creates a PixelArt image generation model.
   * Alias for `image`.
   */
  imageModel(
    modelId: PixelArtImageModelId,
    settings?: PixelArtImageSettings,
  ): ImageModelV3;
}

export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API calls.
   * Defaults to "https://api.pixelart.ai/v1".
   */
  baseURL?: string;

  /**
   * API key for authenticating requests.
   * Falls back to the PIXELART_API_KEY environment variable.
   */
  apiKey?: string;

  /**
   * Custom headers to include in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. You can use it as a middleware to intercept
   * requests, or to provide a custom fetch implementation for testing.
   */
  fetch?: FetchFunction;
}

/**
 * Create a PixelArt provider instance.
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'PIXELART_BASE_URL',
      }),
    ) ?? 'https://api.pixelart.ai/v1';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
